#!/usr/bin/env python3
"""
Test cases for the indicator parameter in merge_asof.
This file contains test cases that should be added to test_merge_asof.py
"""

def test_merge_asof_indicator_true():
    """Test that indicator=True creates _merge column"""
    import pandas as pd
    import pandas._testing as tm

    left = pd.DataFrame(
        {"a": [1, 5, 10], "left_val": ["a", "b", "c"]},
        index=[0, 1, 2]
    )
    right = pd.DataFrame(
        {"a": [1, 2, 3, 6, 7], "right_val": [1, 2, 3, 6, 7]},
        index=[0, 1, 2, 3, 4]
    )

    result = pd.merge_asof(left, right, on="a", indicator=True)

    # Check that _merge column exists
    assert "_merge" in result.columns

    # Check that _merge column has the right values
    assert result["_merge"].dtype.name == "category"
    assert list(result["_merge"].cat.categories) == ["left_only", "right_only", "both"]

    # All rows should be 'both' since all left values match right values
    assert (result["_merge"] == "both").all()

    print("✓ test_merge_asof_indicator_true passed")


def test_merge_asof_indicator_custom_name():
    """Test that indicator can have a custom column name"""
    import pandas as pd

    left = pd.DataFrame(
        {"a": [1, 5, 10], "left_val": ["a", "b", "c"]}
    )
    right = pd.DataFrame(
        {"a": [1, 2, 3, 6, 7], "right_val": [1, 2, 3, 6, 7]}
    )

    result = pd.merge_asof(left, right, on="a", indicator="merge_source")

    # Check that custom column name exists
    assert "merge_source" in result.columns
    assert "_merge" not in result.columns

    # Check that it has the right values
    assert result["merge_source"].dtype.name == "category"
    assert list(result["merge_source"].cat.categories) == ["left_only", "right_only", "both"]

    print("✓ test_merge_asof_indicator_custom_name passed")


def test_merge_asof_indicator_false():
    """Test that indicator=False does not create _merge column (default)"""
    import pandas as pd

    left = pd.DataFrame(
        {"a": [1, 5, 10], "left_val": ["a", "b", "c"]}
    )
    right = pd.DataFrame(
        {"a": [1, 2, 3, 6, 7], "right_val": [1, 2, 3, 6, 7]}
    )

    result = pd.merge_asof(left, right, on="a", indicator=False)

    # Check that _merge column does not exist
    assert "_merge" not in result.columns

    # Also test default (no indicator parameter)
    result_default = pd.merge_asof(left, right, on="a")
    assert "_merge" not in result_default.columns

    print("✓ test_merge_asof_indicator_false passed")


def test_merge_asof_indicator_with_left_only_rows():
    """Test indicator values when there are left_only rows"""
    import pandas as pd

    left = pd.DataFrame(
        {"a": [1, 5, 10, 15], "left_val": ["a", "b", "c", "d"]}
    )
    right = pd.DataFrame(
        {"a": [1, 2, 3, 6, 7], "right_val": [1, 2, 3, 6, 7]}
    )

    result = pd.merge_asof(left, right, on="a", indicator=True)

    # Check that we have both 'both' and 'left_only' values
    unique_values = set(result["_merge"].unique())
    assert "both" in unique_values or "left_only" in unique_values

    print("✓ test_merge_asof_indicator_with_left_only_rows passed")


def test_merge_asof_indicator_by_parameter():
    """Test that indicator works with the 'by' parameter"""
    import pandas as pd
    import numpy as np

    left = pd.DataFrame({
        "time": [1, 5, 10],
        "ticker": ["A", "A", "B"],
        "left_val": [1, 2, 3]
    })

    right = pd.DataFrame({
        "time": [1, 2, 3, 6, 7],
        "ticker": ["A", "A", "A", "A", "B"],
        "right_val": [10, 20, 30, 60, 70]
    })

    result = pd.merge_asof(left, right, on="time", by="ticker", indicator=True)

    # Check that _merge column exists
    assert "_merge" in result.columns

    # Check that it's categorical
    assert result["_merge"].dtype.name == "category"

    print("✓ test_merge_asof_indicator_by_parameter passed")


def test_merge_asof_indicator_conflicting_columns():
    """Test that error is raised if _merge column already exists"""
    import pandas as pd
    from pandas.core.reshape.merge import MergeError

    left = pd.DataFrame({
        "a": [1, 5, 10],
        "left_val": ["a", "b", "c"],
        "_merge": [1, 2, 3]  # Conflicting column
    })
    right = pd.DataFrame({
        "a": [1, 2, 3, 6, 7],
        "right_val": [1, 2, 3, 6, 7]
    })

    try:
        result = pd.merge_asof(left, right, on="a", indicator=True)
        print("✗ test_merge_asof_indicator_conflicting_columns FAILED: Expected error was not raised")
    except ValueError as e:
        if "Cannot use" in str(e) and "existing column" in str(e):
            print("✓ test_merge_asof_indicator_conflicting_columns passed")
        else:
            print(f"✗ test_merge_asof_indicator_conflicting_columns FAILED: Wrong error: {e}")
    except Exception as e:
        print(f"✗ test_merge_asof_indicator_conflicting_columns FAILED: Unexpected error: {e}")


if __name__ == "__main__":
    print("Running indicator tests for merge_asof...")
    print()

    try:
        test_merge_asof_indicator_true()
    except Exception as e:
        print(f"✗ test_merge_asof_indicator_true FAILED: {e}")

    try:
        test_merge_asof_indicator_custom_name()
    except Exception as e:
        print(f"✗ test_merge_asof_indicator_custom_name FAILED: {e}")

    try:
        test_merge_asof_indicator_false()
    except Exception as e:
        print(f"✗ test_merge_asof_indicator_false FAILED: {e}")

    try:
        test_merge_asof_indicator_with_left_only_rows()
    except Exception as e:
        print(f"✗ test_merge_asof_indicator_with_left_only_rows FAILED: {e}")

    try:
        test_merge_asof_indicator_by_parameter()
    except Exception as e:
        print(f"✗ test_merge_asof_indicator_by_parameter FAILED: {e}")

    try:
        test_merge_asof_indicator_conflicting_columns()
    except Exception as e:
        print(f"✗ test_merge_asof_indicator_conflicting_columns FAILED: {e}")

    print()
    print("Test run complete!")

